        for x, y in tetromino.get_tiles():
            if 0 <= x < BOARD_WIDTH and 0 <= y < BOARD_HEIGHT:
                self.grid[y][x] = tetromino.color

    def remove_tetromino(self, tetromino):
        for x, y in tetromino.get_tiles():
            if 0 <= x < BOARD_WIDTH and 0 <= y < BOARD_HEIGHT:
                self.grid[y][x] = 0

    def check_collision(self, tetromino):
        for x, y in tetromino.get_tiles():
            if x < 0 or x >= BOARD_WIDTH or y >= BOARD_HEIGHT or self.grid[y][x] != 0:
                return True
        return False

    def clear_lines(self):
        lines_cleared = 0
        for y in range(BOARD_HEIGHT - 1, -1, -1):
