                            self.tetrominos[self.current_player].rotate()
                            self.tetrominos[self.current_player].rotate()
                            self.tetrominos[self.current_player].rotate()

            self.screen.fill(BLACK)

            for i, board in enumerate(self.boards):
                self.draw_board(board, i * BOARD_WIDTH * TILE_SIZE)
                self.draw_score(board, i * BOARD_WIDTH * TILE_SIZE)

            for i, tetromino in enumerate(self.tetrominos):
