    [(0, 0), (0, 1), (0, 2), (1, 1)],  # T-shaped
]

# Define the colors for each tetromino
TETROMINO_COLORS = [(0, 255, 255), (255, 255, 0), (255, 165, 0), (0, 0, 255), (0, 255, 0), (255, 0, 0), (128, 0, 128)]

class Tetromino:
    def __init__(self, game, x, y, shape_index):
        self.game = game
        self.x = x
        self.y = y
        self.shape_index = shape_index
        self.shape = TETROMINOS[shape_index]
        self.color = TETROMINO_COLORS[shape_index]

    def move_left(self):
        if self.check_collision(self.x - 1, self.y):
            self.x -= 1

    def move_right(self):
        if self.check_collision(self.x + 1, self.y):
            self.x += 1

    def move_down(self):
        if self.check_collision(self.x, self.y + 1):
            self.y += 1
        else:
            self.game.lock_tetromino(self)

    def rotate(self):
        new_shape = [(-y, x) for x, y in self.shape]
        if self.check_collision(self.x, self.y, new_shape):
            self.shape = new_shape

    def check_collision(self, x, y, shape=None):
        if shape is None:
            shape = self.shape
        for dx, dy in shape:
            nx, ny = x + dx, y + dy
            if nx < 0 or nx >= BOARD_WIDTH or ny >= BOARD_HEIGHT or (ny >= 0 and self.game.board[ny][nx]):
                return False
        return True

class TetrisGame:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((800, 600))
        pygame.display.set_caption("Collaborative Tetris")
        self.clock = pygame.time.Clock()
        self.board = [[0 for _ in range(BOARD_WIDTH)] for _ in range(BOARD_HEIGHT)]
        self.current_tetrominos = [Tetromino(self, 4, 0, random.randint(0, len(TETROMINOS) - 1)) for _ in range(3)]
        self.scores = [0, 0, 0]

