        while True:
            self.handle_events()
            self.update()
            self.draw()
            self.clock.tick(60)

    def handle_events(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                pygame.quit()
                quit()
            elif event.type == pygame.KEYDOWN:
                if event.key == pygame.K_LEFT:
                    self.current_tetrominos[0].move_left()
                elif event.key == pygame.K_RIGHT:
                    self.current_tetrominos[0].move_right()
                elif event.key == pygame.K_DOWN:
                    self.current_tetrominos[0].move_down()
                elif event.key == pygame.K_z:
                    self.current_tetrominos[0].rotate()
                elif event.key == pygame.K_a:
                    self.current_tetrominos[1].move_left()
                elif event.key == pygame.K_d:
                    self.current_tetrominos[1].move_right()
                elif event.key == pygame.K_s:
                    self.current_tetrominos[1].move_down()
                elif event.key == pygame.K_q:
                    self.current_tetrominos[1].rotate()
                elif event.key == pygame.K_j:
                    self.current_tetrominos[2].move_left()
                elif event.key == pygame.K_l:
                    self.current_tetrominos[2].move_right()
                elif event.key == pygame.K_k:
                    self.current_tetrominos[2].move_down()
                elif event.key == pygame.K_i:
                    self.current_tetrominos[2].rotate()

    def update(self):
        for i, tetromino in enumerate(self.current_tetrominos):
            tetromino.move_down()
            if not tetromino.check_collision(tetromino.x, tetromino.y):
                self.lock_tetromino(tetromino)
                self.current_tetrominos[i] = Tetromino(self, 4, 0, random.randint(0, len(TETROMINOS) - 1))

        self.clear_lines()

    def lock_tetromino(self, tetromino):
        for dx, dy in tetromino.shape:
            self.board[tetromino.y + dy][tetromino.x + dx] = tetromino.color

    def clear_lines(self):
