                self.board.insert(0, [0] * BOARD_WIDTH)
                lines_cleared += 1

        if lines_cleared > 0:
            self.update_scores(lines_cleared)

    def update_scores(self, lines_cleared):
        for i in range(3):
            self.scores[i] += lines_cleared * (i + 1)

    def draw(self):
        self.screen.fill((0, 0, 0))

        # Draw the game board
        for y in range(BOARD_HEIGHT):
            for x in range(BOARD_WIDTH):
                if self.board[y][x]:
                    pygame.draw.rect(self.screen, self.board[y][x], (x * 30, y * 30, 30, 30))

        # Draw the current tetrominos
