            for dx, dy in tetromino.shape:
                pygame.draw.rect(self.screen, tetromino.color, ((tetromino.x + dx) * 30, (tetromino.y + dy) * 30, 30, 30))

        # Draw the scores
        font = pygame.font.Font(None, 36)
        for i in range(3):
            score_text = font.render(f"Player {i+1} Score: {self.scores[i]}", True, (255, 255, 255))
