    def check_collision(self, tetromino):
        for x, y in tetromino.get_cells():
            if not (0 <= x < self.width and 0 <= y < self.height) or self.grid[y][x]:
                return True
        return False

    def clear_lines(self):
        lines_cleared = 0
        for y in range(self.height - 1, -1, -1):
            if all(self.grid[y]):
                del self.grid[y]
                self.grid.insert(0, [0] * self.width)
                lines_cleared += 1
        return lines_cleared

class Game:
    def __init__(self, player_count):
        self.player_count = player_count
        self.boards = [Board(10, 20) for _ in range(player_count)]
        self.tetrominos = [Tetromino(random.randint(0, 6), 3, 0) for _ in range(player_count)]
        self.scores = [0] * player_count

    def update(self):
        for i in range(self.player_count):
            if not self.boards[i].check_collision(self.tetrominos[i]):
                self.tetrominos[i].move(0, 1)
            else:
                self.boards[i].add_tetromino(self.tetrominos[i])
                lines_cleared = self.boards[i].clear_lines()
                self.scores[i] += lines_cleared * (i + 1)
                self.tetrominos[i] = Tetromino(random.randint(0, 6), 3, 0)

    def get_player_score(self, player_index):
        return self.scores[player_index]

    def get_total_score(self):
        return sum(self.scores)

class GUI:
    def __init__(self, game):
        self.game = game
        self.player_count = game.player_count
        self.width = 800
        self.height = 600
