import pygame
import random

# Define game constants
SCREEN_WIDTH = 800
SCREEN_HEIGHT = 600
BLOCK_SIZE = 30
GRID_WIDTH = 10
GRID_HEIGHT = 20
GAME_SPEED = 1000  # Milliseconds

# Define Tetromino shapes
TETROMINO_SHAPES = [
    [[1, 1, 1, 1]],  # I-Tetromino
    [[1, 1], [1, 1]],  # O-Tetromino
    [[1, 1, 1], [0, 1, 0]],  # T-Tetromino
    [[1, 1, 1], [1, 0, 0]],  # L-Tetromino
    [[1, 1, 1], [0, 0, 1]],  # J-Tetromino
    [[1, 1, 0], [0, 1, 1]],  # S-Tetromino
    [[0, 1, 1], [1, 1, 0]]  # Z-Tetromino
]

# Define colors
COLORS = [(0, 255, 255), (255, 255, 0), (255, 0, 255), (0, 255, 0), (0, 0, 255), (255, 165, 0), (255, 0, 0)]

class Tetromino:
    def __init__(self, shape, color):
        self.shape = shape
        self.color = color
        self.x = 3
        self.y = 0
        self.rotation = 0

    def rotate(self):
        self.rotation = (self.rotation + 1) % len(self.shape)

    def move_left(self):
        self.x = max(self.x - 1, 0)

    def move_right(self):
        self.x = min(self.x + 1, GRID_WIDTH - len(self.shape[0]))

    def move_down(self):
        self.y = min(self.y + 1, GRID_HEIGHT - len(self.shape))

class TetrisGrid:
    def __init__(self):
        self.grid = [[0 for _ in range(GRID_WIDTH)] for _ in range(GRID_HEIGHT)]
        self.current_tetromino = None
        self.next_tetromino = None
        self.score = 0

    def spawn_tetromino(self):
        if self.next_tetromino is None:
            self.next_tetromino = Tetromino(random.choice(TETROMINO_SHAPES), random.choice(COLORS))
        self.current_tetromino = self.next_tetromino
        self.next_tetromino = Tetromino(random.choice(TETROMINO_SHAPES), random.choice(COLORS))

    def check_collision(self, tetromino):
        for y, row in enumerate(tetromino.shape):
            for x, block in enumerate(row):
                if block and (
                    x + tetromino.x < 0 or
                    x + tetromino.x >= GRID_WIDTH or
                    y + tetromino.y >= GRID_HEIGHT or
                    self.grid[y + tetromino.y][x + tetromino.x]
                ):
                    return True
        return False

    def lock_tetromino(self):
        for y, row in enumerate(self.current_tetromino.shape):
            for x, block in enumerate(row):
                if block:
                    self.grid[y + self.current_tetromino.y][x + self.current_tetromino.x] = self.current_tetromino.color
        self.clear_lines()
        self.spawn_tetromino()

    def clear_lines(self):
        rows_to_remove = []
        for y in range(GRID_HEIGHT):
            if all(self.grid[y]):
                rows_to_remove.append(y)

        if rows_to_remove:
            self.score += len(rows_to_remove) ** 2
            for y in reversed(rows_to_remove):
                del self.grid[y]
                self.grid.insert(0, [0] * GRID_WIDTH)

class TetrisGame:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((SCREEN_WIDTH, SCREEN_HEIGHT))
        pygame.display.set_caption("Collaborative Tetris")
        self.clock = pygame.time.Clock()
        self.grids = [TetrisGrid() for _ in range(3)]
        self.player_scores = [0, 0, 0]

    def run(self):
        while True:
            self.handle_events()
            self.update_game()
            self.draw_game()
            self.clock.tick(GAME_SPEED)

    def handle_events(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                pygame.quit()
                quit()

    def update_game(self):
        for i, grid in enumerate(self.grids):
            if grid.current_tetromino is None:
                grid.spawn_tetromino()

            # Move the tetromino down
            grid.current_tetromino.move_down()
            if grid.check_collision(grid.current_tetromino):
                grid.current_tetromino.move_up()
                grid.lock_tetromino()
                self.player_scores[i] += grid.score
                grid.score = 0

            # Handle player input
            keys = pygame.key.get_pressed()
            if keys[pygame.K_LEFT]:
                grid.current_tetromino.move_left()
                if grid.check_collision(grid.current_tetromino):
                    grid.current_tetromino.move_right()
            if keys[pygame.K_RIGHT]:
                grid.current_tetromino.move_right()
                if grid.check_collision(grid.current_tetromino):
                    grid.current_tetromino.move_left()
            if keys[pygame.K_UP]:
                grid.current_tetromino.rotate()
                if grid.check_collision(grid.current_tetromino):
                    grid.current_tetromino.rotate()
                    grid.current_tetromino.rotate()
                    grid.current_tetromino.rotate()

    def draw_game(self):
        self.screen.fill((0, 0, 0))

        for i, grid in enumerate(self.grids):
            x = i * (GRID_WIDTH * BLOCK_SIZE + 50) + 50
            y = 50

            # Draw the grid
            for row_idx, row in enumerate(grid.grid):
                for col_idx, cell in enumerate(row):
                    if cell:
                        pygame.draw.rect(self.screen, cell, (x + col_idx * BLOCK_SIZE, y + row_idx * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))

            # Draw the current tetromino
            if grid.current_tetromino:
                for y, row in enumerate(grid.current_tetromino.shape):
                    for x, block in enumerate(row):
                        if block:
                            pygame.draw.rect(self.screen, grid.current_tetromino.color, (
                                x * BLOCK_SIZE + x + grid.current_tetromino.x * BLOCK_SIZE + x,
                                y * BLOCK_SIZE + y + grid.current_tetromino.y * BLOCK_SIZE + y,
                                BLOCK_SIZE, BLOCK_SIZE
                            ))

            # Draw the next tetromino
            if grid.next_tetromino:
                next_x = x + (GRID_WIDTH + 1) * BLOCK_SIZE
                next_y = y
                for y, row in enumerate(grid.next_tetromino.shape):
                    for x, block in enumerate(row):
                        if block:
                            pygame.draw.rect(self.screen, grid.next_tetromino.color, (
                                x * BLOCK_SIZE + next_x,
                                y * BLOCK_SIZE + next_y,
                                BLOCK_SIZE, BLOCK_SIZE
                            ))

            # Draw the player's score
            font = pygame.font.Font(None, 36)
            score_text = font.render(f"Player {i+1} Score: {self.player_scores[i]}", True, (255, 255, 255))
            self.screen.blit(score_text, (x, y + (GRID_HEIGHT + 1) * BLOCK_SIZE))

        pygame.display.flip()

if __name__ == "__main__":
    game = TetrisGame()
    game.run()

