PLAYER_COUNT = 3

# Colors
COLORS = [(255, 0, 0), (0, 255, 0), (0, 0, 255)]

class Tetromino:
    SHAPES = [
        [(0, 0), (0, 1), (1, 0), (1, 1)],  # Square
        [(0, 0), (0, 1), (0, 2), (0, 3)],  # I-shape
        [(0, 0), (0, 1), (0, 2), (1, 1)],  # T-shape
        [(0, 0), (0, 1), (1, 1), (1, 2)],  # S-shape
        [(0, 0), (0, 1), (1, 0), (1, 1)],  # Z-shape
        [(0, 0), (0, 1), (0, 2), (1, 0)],  # L-shape
        [(0, 0), (0, 1), (0, 2), (1, 2)],  # J-shape
    ]

    def __init__(self, player_index):
        self.shape = random.choice(self.SHAPES)
        self.color = COLORS[player_index]
        self.x = GRID_WIDTH // 2 - 1
        self.y = 0

    def rotate(self):
        self.shape = [(y, -x) for x, y in self.shape]

    def move_left(self):
        self.x -= 1

    def move_right(self):
        self.x += 1

    def move_down(self):
        self.y += 1

class Grid:
    def __init__(self, player_index):
        self.grid = [[0 for _ in range(GRID_WIDTH)] for _ in range(GRID_HEIGHT)]
        self.score = 0
        self.player_index = player_index

    def add_tetromino(self, tetromino):
        for x, y in tetromino.shape:
            self.grid[y + tetromino.y][x + tetromino.x] = tetromino.color
        self.check_lines()

    def check_lines(self):
        lines_cleared = 0
        for y in range(GRID_HEIGHT):
            if all(self.grid[y]):
                self.grid.pop(y)
                self.grid.insert(0, [0] * GRID_WIDTH)
                lines_cleared += 1
        self.score += lines_cleared ** 2 * (self.player_index + 1)

    def can_move(self, tetromino, dx=0, dy=0):
        for x, y in tetromino.shape:
            new_x, new_y = x + tetromino.x + dx, y + tetromino.y + dy
            if new_x < 0 or new_x >= GRID_WIDTH or new_y >= GRID_HEIGHT or self.grid[new_y][new_x]:
                return False
        return True

class TetrisGame:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((WINDOW_WIDTH, WINDOW_HEIGHT))
        pygame.display.set_caption("Collaborative Tetris")
        self.clock = pygame.time.Clock()
        self.grids = [Grid(i) for i in range(PLAYER_COUNT)]
        self.tetrominos = [Tetromino(i) for i in range(PLAYER_COUNT)]
        self.game_over = False

    def run(self):
        while not self.game_over:
            self.handle_events()
            self.update()
            self.draw()
            self.clock.tick(60)

        pygame.quit()

    def handle_events(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                self.game_over = True
            elif event.type == pygame.KEYDOWN:
                if event.key == pygame.K_LEFT:
                    self.move_tetromino(-1, 0)
                elif event.key == pygame.K_RIGHT:
                    self.move_tetromino(1, 0)
                elif event.key == pygame.K_UP:
                    self.rotate_tetromino()
                elif event.key == pygame.K_DOWN:
                    self.move_tetromino(0, 1)

    def update(self):
        for i in range(PLAYER_COUNT):
            if not self.grids[i].can_move(self.tetrominos[i], 0, 1):
                self.grids[i].add_tetromino(self.tetrominos[i])
                self.tetrominos[i] = Tetromino(i)
            else:
                self.tetrominos[i].move_down()

    def move_tetromino(self, dx, dy):
        for i in range(PLAYER_COUNT):
            if self.grids[i].can_move(self.tetrominos[i], dx, dy):
                self.tetrominos[i].x += dx
                self.tetrominos[i].y += dy

    def rotate_tetromino(self):
        for i in range(PLAYER_COUNT):
            temp_tetromino = Tetromino(i)
            temp_tetromino.shape = self.tetrominos[i].shape
            temp_tetromino.x = self.tetrominos[i].x
            temp_tetromino.y = self.tetrominos[i].y
            temp_tetromino.rotate()
            if self.grids[i].can_move(temp_tetromino):
                self.tetrominos[i].rotate()

    def draw(self):
        self.screen.fill((0, 0, 0))

        for i in range(PLAYER_COUNT):
            for y in range(GRID_HEIGHT):
                for x in range(GRID_WIDTH):
                    if self.grids[i].grid[y][x]:
                        rect = pygame.Rect(x * BLOCK_SIZE + i * GRID_WIDTH * BLOCK_SIZE + 50, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE)
                        pygame.draw.rect(self.screen, self.grids[i].grid[y][x], rect)

            for x, y in self.tetrominos[i].shape:
                rect = pygame.Rect((x + self.tetrominos[i].x) * BLOCK_SIZE + i * GRID_WIDTH * BLOCK_SIZE + 50, (y + self.tetrominos[i].y) * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE)
                pygame.draw.rect(self.screen, self.tetrominos[i].color, rect)

            score_text = pygame.font.Font(None, 36).render(f"Player {i+1} Score: {self.grids[i].score}", True, (255, 255, 255))
            self.screen.blit(score_text, (i * GRID_WIDTH * BLOCK_SIZE + 50, GRID_HEIGHT * BLOCK_SIZE + 50))

        pygame.display.flip()

