        self.shape_index = shape_index
        self.rotation_index = rotation_index
        self.x = x
        self.y = y

    def get_shape(self):
        return self.SHAPES[self.shape_index][self.rotation_index]

    def rotate(self):
        self.rotation_index = (self.rotation_index + 1) % len(self.SHAPES[self.shape_index])

    def move(self, dx, dy):
        self.x += dx
        self.y += dy

class Board:
