        self.after(1000, self.game_loop)

    def game_loop(self):
        self.move_tetromino()
        self.render_game()
        self.after(500, self.game_loop)

    def move_tetromino(self):
        if not self.board1.check_collision():
            self.board1.move_tetromino(0, 1)
        else:
            self.board1.lock_tetromino()

        if not self.board2.check_collision():
            self.board2.move_tetromino(0, 1)
        else:
            self.board2.lock_tetromino()

        if not self.board3.check_collision():
            self.board3.move_tetromino(0, 1)
        else:
            self.board3.lock_tetromino()

    def render_game(self):
        self.canvas.delete("all")
        self.render_board(self.board1, 0, 0)
        self.render_board(self.board2, self.board_width * self.cell_size, 0)
        self.render_board(self.board3, self.board_width * self.cell_size * 2, 0)

    def render_board(self, board, x_offset, y_offset):
        for y in range(board.height):
            for x in range(board.width):
                if board.grid[y][x]:
                    self.canvas.create_rectangle(
                        x * self.cell_size + x_offset,
                        y * self.cell_size + y_offset,
                        (x + 1) * self.cell_size + x_offset,
                        (y + 1) * self.cell_size + y_offset,
                        fill="blue"
                    )

        tetromino = board.current_tetromino
        if tetromino:
