        self.x = GRID_WIDTH // 2 - 1
        self.y = 0
        self.rotation = 0

    def move_left(self):
        if self.can_move_left():
            self.x -= 1

    def move_right(self):
        if self.can_move_right():
            self.x += 1

    def move_down(self):
        if self.can_move_down():
            self.y += 1
        else:
            self.lock_in_place()

    def rotate(self):
        if self.can_rotate():
            self.rotation = (self.rotation + 1) % 4

    def can_move_left(self):
        for x, y in self.get_blocks():
            if x == 0 or game_grid[y][x - 1] != 0:
                return False
        return True

    def can_move_right(self):
        for x, y in self.get_blocks():
            if x == GRID_WIDTH - 1 or game_grid[y][x + 1] != 0:
                return False
        return True

    def can_move_down(self):
        for x, y in self.get_blocks():
            if y == GRID_HEIGHT - 1 or game_grid[y + 1][x] != 0:
                return False
        return True

    def can_rotate(self):
        # Perform a dry run of the rotation
        new_shape = self.get_rotated_shape()
        for x, y in new_shape:
            if x < 0 or x >= GRID_WIDTH or y >= GRID_HEIGHT or game_grid[y][x] != 0:
                return False
        return True

    def get_blocks(self):
        blocks = []
        for x, y in self.shape[self.rotation]:
            blocks.append((self.x + x, self.y + y))
        return blocks

    def get_rotated_shape(self):
        return [(-y, x) for x, y in self.shape[self.rotation]]

    def lock_in_place(self):
        for x, y in self.get_blocks():
            game_grid[y][x] = self.color
        new_tetromino()

def new_tetromino():
