    [(0, 0), (0, 1), (1, 0), (1, 1)],  # Square
    [(0, 0), (0, 1), (0, 2), (0, 3)],  # I-shape
    [(0, 0), (0, 1), (0, 2), (1, 2)],  # L-shape
    [(0, 0), (0, 1), (0, 2), (1, 0)],  # J-shape
    [(0, 0), (0, 1), (1, 1), (1, 2)],  # S-shape
    [(0, 0), (0, 1), (1, 0), (1, 1)],  # Z-shape
    [(0, 0), (0, 1), (0, 2), (1, 1)],  # T-shape
]

# Define the colors for each shape
COLORS = [(255, 0, 0), (0, 255, 0), (0, 0, 255), (255, 255, 0), (255, 0, 255), (0, 255, 255), (255, 165, 0)]

class Tetromino:
    def __init__(self, shape_index, x, y):
        self.shape = SHAPES[shape_index]
        self.color = COLORS[shape_index]
        self.x = x
        self.y = y
        self.rotation = 0

    def rotate(self):
        self.rotation = (self.rotation + 1) % 4
        self.shape = [(-y, x) for x, y in self.shape]

    def move(self, dx, dy):
        self.x += dx
        self.y += dy

class TetrisGame:
    def __init__(self, player_count):
        self.player_count = player_count
        self.players = [Player(i) for i in range(player_count)]
        self.current_player_index = 0
        self.board = [[0 for _ in range(BOARD_WIDTH)] for _ in range(BOARD_HEIGHT)]
        self.active_tetromino = self.new_tetromino()
        self.score = [0] * player_count

    def new_tetromino(self):
        shape_index = random.randint(0, len(SHAPES) - 1)
        return Tetromino(shape_index, BOARD_WIDTH // 2 - 2, 0)

    def update(self):
        self.active_tetromino.move(0, 1)
        if self.check_collision():
            self.lock_tetromino()
            self.clear_lines()
            self.active_tetromino = self.new_tetromino()
            self.current_player_index = (self.current_player_index + 1) % self.player_count

    def check_collision(self):
        for x, y in self.active_tetromino.shape:
            new_x = self.active_tetromino.x + x
            new_y = self.active_tetromino.y + y
            if new_y >= BOARD_HEIGHT or self.board[new_y][new_x] != 0:
                return True
        return False

    def lock_tetromino(self):
        for x, y in self.active_tetromino.shape:
            self.board[self.active_tetromino.y + y][self.active_tetromino.x + x] = self.active_tetromino.color

    def clear_lines(self):
        rows_to_remove = []
        for y in range(BOARD_HEIGHT):
            if all(self.board[y]):
                rows_to_remove.append(y)

        if rows_to_remove:
            self.players[self.current_player_index].score += len(rows_to_remove) ** 2
            for y in reversed(rows_to_remove):
                del self.board[y]
                self.board.insert(0, [0] * BOARD_WIDTH)

class Player:
    def __init__(self, index):
        self.index = index
        self.score = 0

    def update(self, game):
        if game.current_player_index == self.index:
            keys = pygame.key.get_pressed()
            if keys[pygame.K_LEFT]:
                game.active_tetromino.move(-1, 0)
                if game.check_collision():
                    game.active_tetromino.move(1, 0)
            elif keys[pygame.K_RIGHT]:
                game.active_tetromino.move(1, 0)
                if game.check_collision():
                    game.active_tetromino.move(-1, 0)
            elif keys[pygame.K_DOWN]:
                game.active_tetromino.move(0, 1)
                if game.check_collision():
                    game.active_tetromino.move(0, -1)
            elif keys[pygame.K_SPACE]:
                while not game.check_collision():
                    game.active_tetromino.move(0, 1)
                game.active_tetromino.move(0, -1)
            elif keys[pygame.K_UP]:
                game.active_tetromino.rotate()
                if game.check_collision():
                    game.active_tetromino.rotate()
                    game.active_tetromino.rotate()
                    game.active_tetromino.rotate()

