import pygame
import random

# Define colors
BLACK = (0, 0, 0)
WHITE = (255, 255, 255)
GRAY = (128, 128, 128)
BLUE = (0, 0, 255)
GREEN = (0, 255, 0)
RED = (255, 0, 0)

# Define block shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I-shape
    [[1, 1], [1, 1]],  # O-shape
    [[1, 1, 1], [0, 1, 0]],  # T-shape
    [[1, 1, 0], [0, 1, 1]],  # S-shape
    [[0, 1, 1], [1, 1, 0]],  # Z-shape
    [[1, 0, 0], [1, 1, 1]],  # J-shape
    [[0, 0, 1], [1, 1, 1]]  # L-shape
]

# Define game board dimensions
BOARD_WIDTH = 10
BOARD_HEIGHT = 20

class Tetromino:
    def __init__(self, shape, color):
        self.shape = shape
        self.color = color
        self.x = BOARD_WIDTH // 2 - len(shape[0]) // 2
        self.y = 0
        self.rotation = 0

    def rotate(self):
        self.rotation = (self.rotation + 1) % len(self.shape)

    def move(self, dx, dy):
        self.x += dx
        self.y += dy

class Player:
    def __init__(self, name, x, y):
        self.name = name
        self.x = x
        self.y = y
        self.board = [[0 for _ in range(BOARD_WIDTH)] for _ in range(BOARD_HEIGHT)]
        self.current_tetromino = None
        self.score = 0

    def spawn_tetromino(self):
        shape = random.choice(SHAPES)
        color = random.choice([BLUE, GREEN, RED])
        self.current_tetromino = Tetromino(shape, color)

    def update(self):
        if self.current_tetromino is None:
            self.spawn_tetromino()

        # Move the current tetromino down
        if self.can_move_down():
            self.current_tetromino.move(0, 1)
        else:
            self.lock_tetromino()
            self.clear_lines()
            self.spawn_tetromino()

    def can_move_down(self):
        tetromino = self.current_tetromino
        for y in range(len(tetromino.shape)):
            for x in range(len(tetromino.shape[y])):
                if tetromino.shape[y][x] == 1:
                    new_y = tetromino.y + y + 1
                    new_x = tetromino.x + x
                    if new_y >= BOARD_HEIGHT or self.board[new_y][new_x] != 0:
                        return False
        return True

    def lock_tetromino(self):
        tetromino = self.current_tetromino
        for y in range(len(tetromino.shape)):
            for x in range(len(tetromino.shape[y])):
                if tetromino.shape[y][x] == 1:
                    new_y = tetromino.y + y
                    new_x = tetromino.x + x
                    self.board[new_y][new_x] = tetromino.color
        self.current_tetromino = None

    def clear_lines(self):
        rows_to_clear = []
        for y in range(BOARD_HEIGHT):
            if all(self.board[y]):
                rows_to_clear.append(y)

        if rows_to_clear:
            self.score += len(rows_to_clear) ** 2
            for y in reversed(rows_to_clear):
                del self.board[y]
                self.board.insert(0, [0] * BOARD_WIDTH)

    def draw(self, screen):
        # Draw the player's board
        for y in range(BOARD_HEIGHT):
            for x in range(BOARD_WIDTH):
                if self.board[y][x] != 0:
                    pygame.draw.rect(screen, self.board[y][x], (self.x + x * 20, self.y + y * 20, 20, 20))

        # Draw the current tetromino
        if self.current_tetromino is not None:
            tetromino = self.current_tetromino
            for y in range(len(tetromino.shape)):
                for x in range(len(tetromino.shape[y])):
                    if tetromino.shape[y][x] == 1:
                        pygame.draw.rect(screen, tetromino.color, (self.x + (tetromino.x + x) * 20, self.y + (tetromino.y + y) * 20, 20, 20))

