import pygame
import random

# Define the Tetris block shapes
SHAPES = [
    [(0,0),(0,1),(1,0),(1,1)], # Square
    [(0,0),(0,1),(0,2),(0,3)], # I-piece
    [(0,0),(0,1),(0,2),(1,2)], # L-piece
    [(0,0),(0,1),(0,2),(1,0)], # J-piece
    [(0,0),(0,1),(1,1),(1,2)], # S-piece
    [(0,0),(0,1),(1,0),(1,1)], # Z-piece
    [(0,0),(0,1),(0,2),(1,1)]  # T-piece
]

# Define the Tetris board size
BOARD_WIDTH = 10
BOARD_HEIGHT = 20

# Define the player colors
PLAYER_COLORS = [(255,0,0), (0,255,0), (0,0,255)]

class TetrisGame:
    def __init__(self):
        # Initialize Pygame
        pygame.init()
        self.screen = pygame.display.set_mode((BOARD_WIDTH*30, BOARD_HEIGHT*30))
        pygame.display.set_caption("Collaborative Tetris")

        # Initialize the game state
        self.players = [Player(i) for i in range(3)]
        self.current_player = 0
        self.game_over = False

    def run(self):
        clock = pygame.time.Clock()
        while not self.game_over:
            # Handle events
            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    self.game_over = True
                elif event.type == pygame.KEYDOWN:
                    self.players[self.current_player].handle_input(event.key)

            # Update the game state
            self.players[self.current_player].update()

            # Check for game over conditions
            if any(player.is_game_over() for player in self.players):
                self.game_over = True

            # Render the game
            self.render()

            # Switch to the next player
            self.current_player = (self.current_player + 1) % len(self.players)

            # Limit the frame rate
            clock.tick(60)

        # Display the final score
        self.display_final_score()

    def render(self):
        # Clear the screen
        self.screen.fill((0,0,0))

        # Render the player boards
        for i, player in enumerate(self.players):
            player.render(self.screen, i)

        # Update the display
        pygame.display.flip()

    def display_final_score(self):
        # Calculate the overall score
        total_score = sum(player.score for player in self.players)
        score_message = f"Final Score: {total_score}"

        # Render the final score message
        font = pygame.font.Font(None, 36)
        text = font.render(score_message, True, (255,255,255))
        text_rect = text.get_rect(center=(BOARD_WIDTH*15, BOARD_HEIGHT*15))
        self.screen.blit(text, text_rect)
        pygame.display.flip()

        # Wait for the user to close the window
        while True:
            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    pygame.quit()
                    return

class Player:
    def __init__(self, player_id):
        self.player_id = player_id
        self.board = [[0 for _ in range(BOARD_WIDTH)] for _ in range(BOARD_HEIGHT)]
        self.current_shape = self.new_shape()
        self.x = BOARD_WIDTH // 2 - 2
        self.y = 0
        self.score = 0
        self.game_over = False

    def new_shape(self):
        return random.choice(SHAPES)

    def handle_input(self, key):
        if key == pygame.K_LEFT:
            self.move(-1, 0)
        elif key == pygame.K_RIGHT:
            self.move(1, 0)
        elif key == pygame.K_DOWN:
            self.move(0, 1)
        elif key == pygame.K_UP:
            self.rotate()

    def move(self, dx, dy):
        new_x = self.x + dx
        new_y = self.y + dy
        if self.can_move(new_x, new_y):
            self.x = new_x
            self.y = new_y

    def rotate(self):
        new_shape = [[(y, -x) for x, y in block] for block in self.current_shape]
        if self.can_move(self.x, self.y, new_shape):
            self.current_shape = new_shape

    def can_move(self, x, y, shape=None):
        if shape is None:
            shape = self.current_shape
        for dx, dy in shape:
            new_x, new_y = x + dx, y + dy
            if new_x < 0 or new_x >= BOARD_WIDTH or new_y >= BOARD_HEIGHT or self.board[new_y][new_x]:
                return False
        return True

    def update(self):
        if self.can_move(self.x, self.y + 1):
            self.y += 1
        else:
            self.lock_shape()
            self.check_for_completed_lines()
            self.current_shape = self.new_shape()
            self.x = BOARD_WIDTH // 2 - 2
            self.y = 0
            if not self.can_move(self.x, self.y):
                self.game_over = True

    def lock_shape(self):
        for dx, dy in self.current_shape:
            x, y = self.x + dx, self.y + dy
            self.board[y][x] = self.player_id + 1

    def check_for_completed_lines(self):
        lines_cleared = 0
        for y in range(BOARD_HEIGHT - 1, -1, -1):
            if all(self.board[y]):
                del self.board[y]
                self.board.insert(0, [0] * BOARD_WIDTH)
                lines_cleared += 1
        self.score += [0, 40, 100, 300, 1200][lines_cleared]

    def is_game_over(self):
        return self.game_over

    def render(self, screen, player_index):
        # Render the player's board
        for y in range(BOARD_HEIGHT):
            for x in range(BOARD_WIDTH):
                if self.board[y][x]:
                    color = PLAYER_COLORS[self.board[y][x] - 1]
                    pygame.draw.rect(screen, color, (x*30, y*30, 30, 30))

        # Render the current shape
        for dx, dy in self.current_shape:
            pygame.draw.rect(screen, PLAYER_COLORS[player_index], ((self.x + dx)*30, (self.y + dy)*30, 30, 30))

        # Render the player's score
        font = pygame.font.Font(None, 36)
        text = font.render(f"Player {player_index + 1} Score: {self.score}", True, PLAYER_COLORS[player_index])
        text_rect = text.get_rect(topleft=(BOARD_WIDTH*30 + 20, player_index * 50))
        screen.blit(text, text_rect)

if __name__ == "__main__":
    game = TetrisGame()
    game.run()

