BOARD_HEIGHT = 20

# Define the player colors
PLAYER_COLORS = [(255, 0, 0), (0, 255, 0), (0, 0, 255)]

class Tetromino:
    def __init__(self, shape_index, position):
        self.shape = SHAPES[shape_index]
        self.position = position
        self.rotation = 0

    def rotate(self):
