    def move(self, dx, dy):
        self.position = (self.position[0] + dx, self.position[1] + dy)

class Player:
    def __init__(self, color):
        self.color = color
        self.score = 0
        self.board = [[0 for _ in range(BOARD_WIDTH)] for _ in range(BOARD_HEIGHT)]
        self.current_tetromino = None
        self.next_tetromino = Tetromino(random.randint(0, len(SHAPES) - 1), (3, 0))

    def update_board(self, tetromino):
        for y in range(4):
            for x in range(4):
                if tetromino.shape[tetromino.rotation][y][x]:
                    self.board[tetromino.position[1] + y][tetromino.position[0] + x] = tetromino.color

    def clear_lines(self):
        lines_cleared = 0
        for y in range(BOARD_HEIGHT - 1, -1, -1):
            if all(self.board[y]):
                self.board.pop(y)
                self.board.insert(0, [0 for _ in range(BOARD_WIDTH)])
                lines_cleared += 1
        self.score += lines_cleared ** 2 * 100

    def start_new_tetromino(self):
        self.current_tetromino = self.next_tetromino
        self.next_tetromino = Tetromino(random.randint(0, len(SHAPES) - 1), (3, 0))
        self.current_tetromino.color = self.color

