        self.width, self.height = width, height
        self.grid = [[0 for x in range(width)] for y in range(height)]

    def place(self, tetromino):
        for x, y in tetromino.shape:
            self.grid[y+tetromino.y][x+tetromino.x] = 1

    def check_collision(self, tetromino):
        for x, y in tetromino.shape:
            if x+tetromino.x < 0 or x+tetromino.x >= self.width or y+tetromino.y >= self.height or self.grid[y+tetromino.y][x+tetromino.x]:
                return True
        return False

    def clear_lines(self):
        lines_cleared = 0
        for y in range(self.height-1, -1, -1):
            if all(self.grid[y]):
