        self.tetrominos = []
        self.scores = [0, 0, 0]

    def add_tetromino(self, tetromino):
        self.tetrominos.append(tetromino)

    def check_collision(self, tetromino):
        for y, row in enumerate(tetromino.shape[tetromino.orientation]):
            for x, block in enumerate(row):
                if block and (tetromino.x + x < 0 or tetromino.x + x >= self.width or tetromino.y + y >= self.height or self.board[tetromino.y + y][tetromino.x + x]):
                    return True
        return False

    def update_board(self):
        for tetromino in self.tetrominos:
            for y, row in enumerate(tetromino.shape[tetromino.orientation]):
                for x, block in enumerate(row):
                    if block:
                        self.board[tetromino.y + y][tetromino.x + x] = 1

    def clear_lines(self):
        lines_cleared = 0
        for y in range(self.height - 1, -1, -1):
            if all(self.board[y]):
                self.board.pop(y)
                self.board.insert(0, [0] * self.width)
                lines_cleared += 1
        for i in range(lines_cleared):
            self.scores[i % 3] += 10

    def game_over(self):
        for tetromino in self.tetrominos:
            if tetromino.y < 0:
