    def add_piece(self, player_index):
        piece = random.choice(["I", "O", "T", "S", "Z", "J", "L"])
        self.active_pieces.append((piece, player_index, 0, 4))

    def move_piece(self, player_index, direction):
        for i, (piece, p_index, row, col) in enumerate(self.active_pieces):
            if p_index == player_index:
                if direction == "left":
                    if col > 0 and self.board[row][col - 1] == 0:
                        self.active_pieces[i] = (piece, p_index, row, col - 1)
                elif direction == "right":
                    if col < 9 and self.board[row][col + 1] == 0:
                        self.active_pieces[i] = (piece, p_index, row, col + 1)
                elif direction == "down":
                    if row < 19 and self.board[row + 1][col] == 0:
                        self.active_pieces[i] = (piece, p_index, row + 1, col)
                elif direction == "rotate":
                    if piece == "I":
                        self.active_pieces[i] = (piece, p_index, col, 19 - row)
                    else:
                        self.active_pieces[i] = (piece, p_index, 19 - col, row)

    def update_board(self):
        for piece, player_index, row, col in self.active_pieces:
            self.board[row][col] = player_index + 1
        self.active_pieces = [(piece, player_index, row + 1, col) for piece, player_index, row, col in self.active_pieces if row < 19 and self.board[row + 1][col] == 0]

    def check_lines(self):
        lines_cleared = 0
        for row in range(19, -1, -1):
            if all(self.board[row]):
                self.board.pop(row)
                self.board.insert(0, [0] * 10)
                lines_cleared += 1
                for i, (piece, player_index, r, c) in enumerate(self.active_pieces):
                    if r < row:
                        self.active_pieces[i] = (piece, player_index, r + 1, c)
        return lines_cleared

    def update_scores(self, lines_cleared):
        for i in range(len(self.players)):
            self.scores[i] += lines_cleared * (i + 1)

    def play_round(self):
        for i in range(len(self.players)):
            self.add_piece(i)
        while self.active_pieces:
            for i in range(len(self.players)):
                self.move_piece(i, random.choice(["left", "right", "down", "rotate"]))
            self.update_board()
            lines_cleared = self.check_lines()
            self.update_scores(lines_cleared)

    def get_scores(self):
