class BaseballLeague:
    def __init__(self, name):
        self.name = name
        self.players = []
        self.game_history = []

    def add_player(self, player):
        self.players.append(player)

    def play_game(self, home_team, away_team):
        home_score = random.randint(0, 10)
        away_score = random.randint(0, 10)

        for player in self.players:
            if player.team == home_team:
                hits = random.randint(0, 3)
                runs = random.randint(0, 2)
                rbis = random.randint(0, 2)
                player.update_stats(hits, runs, rbis)
            elif player.team == away_team:
                hits = random.randint(0, 3)
                runs = random.randint(0, 2)
                rbis = random.randint(0, 2)
                player.update_stats(hits, runs, rbis)

        game_info = {
            'date': datetime.datetime.now().strftime('%Y-%m-%d'),
            'home_team': home_team,
            'away_team': away_team,
            'home_score': home_score,
            'away_score': away_score
        }
        self.game_history.append(game_info)

    def get_player_stats(self, player_name):
        for player in self.players:
            if player.name == player_name:
                return player.get_stats()
        return None

    def get_team_standings(self):
        team_standings = {}
        for player in self.players:
            if player.team not in team_standings:
                team_standings[player.team] = {
                    'wins': 0,
                    'losses': 0,
                    'runs_scored': 0,
                    'runs_allowed': 0
                }

            team_standings[player.team]['runs_scored'] += player.stats['runs']

        for game in self.game_history:
            team_standings[game['home_team']]['runs_allowed'] += game['away_score']
            team_standings[game['away_team']]['runs_allowed'] += game['home_score']

            if game['home_score'] > game['away_score']:
                team_standings[game['home_team']]['wins'] += 1
                team_standings[game['away_team']]['losses'] += 1
            else:
                team_standings[game['away_team']]['wins'] += 1
                team_standings[game['home_team']]['losses'] += 1

        return team_standings

